const fetch = require('node-fetch');
const cheerio = require('cheerio');

async function fetchMetadata(url) {
  const metadata = {
    title: null,
    description: null,
    ogTags: {},
    error: null,
  };

  try {
    if (!url || typeof url !== 'string' || !/^https?:\/\//i.test(url)) {
      metadata.error = 'Invalid URL provided.';
      return metadata;
    }

    const response = await fetch(url, {
      timeout: 10000,
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; Googlebot/2.1; +http://www.google.com/bot.html)',
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8'
      }
    });

    if (!response.ok) {
      metadata.error = `HTTP error! Status: ${response.status} - ${response.statusText}`;
      return metadata;
    }

    const contentType = response.headers.get('content-type');
    if (!contentType || !contentType.includes('text/html')) {
        metadata.error = 'URL does not point to an HTML document.';
        return metadata;
    }

    const html = await response.text();

    const $ = cheerio.load(html);

    metadata.title = $('title').text() || null;

    metadata.description = $('meta[name="description"]').attr('content') || null;

    $('meta[property^="og:"]').each((i, el) => {
      const property = $(el).attr('property');
      const content = $(el).attr('content');
      if (property && content) {
        const key = property.replace('og:', '');
        metadata.ogTags[key] = content;
      }
    });

  } catch (err) {
    console.error(`Error fetching metadata for ${url}:`, err.message);
    metadata.error = `Failed to fetch metadata: ${err.message}`;
  }

  return metadata;
}

module.exports = fetchMetadata;